//! AOT-tier coverage report over the gnode benchmark corpus.
//!
//! For every extractable export in `gnode/benchmarks/*` this asks each
//! AOT lane's PUBLIC support surface whether it would claim the export:
//!
//! - Tier A  — direct wasm-encoder emission (`aot_wasm::supports_wasm_for_export`)
//! - Tier A/C — native C AOT (`aot_c::supports_c_for_export`)
//! - Tier B  — clang-freestanding wasm-via-C (`aot_wasm_c::compile_wasm_via_c`;
//!   probed only when a wasm32-capable clang is on PATH)
//! - Tier C  — gg-walker interpreter-embed
//!   (`aot_gg_embed::supports_gg_embed_for_export` — the walker's own static
//!   admission sweep runs natively; no prebuilt walker binary required)
//!
//! Run via `scripts/coverage-report.sh` or
//! `cargo run --example coverage_report`.

use std::fs;
use std::path::Path;

use gnosis_polyglot::aot_c::supports_c_for_export;
use gnosis_polyglot::aot_gg_embed::supports_gg_embed_for_export;
use gnosis_polyglot::aot_wasm::supports_wasm_for_export;
use gnosis_polyglot::aot_wasm_c::{compile_wasm_via_c, wasm_clang};

fn main() {
    let manifest_dir = env!("CARGO_MANIFEST_DIR");
    let bench_dir = Path::new(manifest_dir).join("../gnode/benchmarks");
    let clang = wasm_clang();

    let mut paths: Vec<_> = fs::read_dir(&bench_dir)
        .expect("gnode/benchmarks should be readable")
        .filter_map(|entry| entry.ok())
        .map(|entry| entry.path())
        .filter(|path| {
            matches!(
                path.extension().and_then(|e| e.to_str()),
                Some("ts" | "py" | "rs" | "go" | "rb" | "java" | "kt" | "gg" | "gnot")
            )
        })
        .collect();
    paths.sort();

    println!("AOT tier coverage — gnode/benchmarks");
    println!(
        "tiers: A = direct wasm (aot_wasm) | A/C = native C (aot_c) | B = wasm-via-C (aot_wasm_c{}) | C = gg-embed (aot_gg_embed)",
        if clang.is_some() {
            ""
        } else {
            "; no wasm32 clang found, probes skipped"
        }
    );
    println!();
    println!(
        "{:<28} {:<20} {:^4} {:^4} {:^4} {:^4}",
        "file", "export", "A", "A/C", "B", "C"
    );

    let mut exports_total = 0usize;
    let mut exports_any = 0usize;
    let mut per_tier = [0usize; 4];

    for path in paths {
        let file_name = path
            .file_name()
            .map(|n| n.to_string_lossy().to_string())
            .unwrap_or_default();
        let Ok(source) = fs::read_to_string(&path) else {
            continue;
        };
        let path_str = path.to_string_lossy().to_string();
        let Ok(scan) = gnosis_polyglot::parse_and_extract_orchestration(&source, &path_str) else {
            println!("{file_name:<28} {:<20} {:^4} {:^4} {:^4}", "(no extract)", "-", "-", "-");
            continue;
        };
        let mut seen = std::collections::HashSet::new();
        for topology in &scan.scan_result.topologies {
            let export = topology.function_name.clone();
            if !seen.insert(export.clone()) {
                continue;
            }
            let tier_a = supports_wasm_for_export(&scan, &source, &export);
            let tier_ac = supports_c_for_export(&scan, &source, &export);
            let tier_b = clang.is_some() && compile_wasm_via_c(&source, &export).is_ok();
            let tier_c = supports_gg_embed_for_export(&scan, &export);

            exports_total += 1;
            if tier_a || tier_ac || tier_b || tier_c {
                exports_any += 1;
            }
            for (index, hit) in [tier_a, tier_ac, tier_b, tier_c].into_iter().enumerate() {
                if hit {
                    per_tier[index] += 1;
                }
            }
            let mark = |hit: bool| if hit { "x" } else { "." };
            println!(
                "{file_name:<28} {export:<20} {:^4} {:^4} {:^4} {:^4}",
                mark(tier_a),
                mark(tier_ac),
                mark(tier_b),
                mark(tier_c)
            );
        }
    }

    println!();
    if exports_total == 0 {
        println!("no extractable exports found");
        return;
    }
    println!(
        "totals: {exports_total} exports | tier A {} | tier A/C {} | tier B {} | tier C {} | any tier {} ({}%)",
        per_tier[0],
        per_tier[1],
        per_tier[2],
        per_tier[3],
        exports_any,
        exports_any * 100 / exports_total
    );
}
